      <div className="flex items-center gap-2 mb-3">{icon}<span className="text-xs text-gray-500 font-medium">{label}</span></div>
      <p className="text-2xl font-bold text-white">{value}</p>
    </div>
  );
}

export default Integrations;

import React, { useState, useEffect, useCallback } from 'react';
import {
  ArrowLeft, Key, Webhook as WebhookIcon, BarChart3, BookOpen, Copy, Check,
  Plus, Trash2, RefreshCw, ChevronDown, ChevronRight, Zap, Shield, Terminal,
  Activity, AlertTriangle, Clock, ToggleLeft, ToggleRight, Code2, Globe,
} from 'lucide-react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend,
} from 'recharts';
import { User } from '../types';
import {
  ApiKey, Webhook, WebhookEvent, ApiEndpoint, ApiUsageDay,
} from '../types/api-developer';
import {
  getApiKeys, createApiKey, revokeApiKey, regenerateApiKey,
  getWebhooks, createWebhook, deleteWebhook, toggleWebhook,
  getEndpoints, getUsageData, getUsageStats,
} from '../services/api-developer';
import PageHeader from '../components/layout/PageHeader';
import { useTranslation } from '../i18n/context';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

type Tab = 'docs' | 'keys' | 'webhooks' | 'usage';

const ApiDeveloper: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const { t } = useTranslation();

  const TABS: { id: Tab; label: string; icon: React.ElementType }[] = [
    { id: 'docs', label: t.apiDeveloperPage.tabDocs, icon: BookOpen },
    { id: 'keys', label: t.apiDeveloperPage.tabKeys, icon: Key },
    { id: 'webhooks', label: t.apiDeveloperPage.tabWebhooks, icon: WebhookIcon },
    { id: 'usage', label: t.apiDeveloperPage.tabUsage, icon: BarChart3 },
  ];

  const WEBHOOK_EVENTS: { value: WebhookEvent; label: string }[] = [
    { value: 'audit.completed', label: t.apiDeveloperPage.eventAuditCompleted },
    { value: 'monitoring.scan_completed', label: t.apiDeveloperPage.eventScanCompleted },
    { value: 'monitoring.alert', label: t.apiDeveloperPage.eventMonitoringAlert },
    { value: 'credits.low', label: t.apiDeveloperPage.eventCreditsLow },
    { value: 'citations.new', label: t.apiDeveloperPage.eventNewCitation },
  ];

  const EVENT_COLORS: Record<WebhookEvent, string> = {
    'audit.completed': 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
    'monitoring.scan_completed': 'bg-blue-500/10 text-blue-400 border-blue-500/20',
    'monitoring.alert': 'bg-amber-500/10 text-amber-400 border-amber-500/20',
    'credits.low': 'bg-red-500/10 text-red-400 border-red-500/20',
    'citations.new': 'bg-purple-500/10 text-purple-400 border-purple-500/20',
  };

  const [activeTab, setActiveTab] = useState<Tab>('docs');
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Keys state
  const [keys, setKeys] = useState<ApiKey[]>([]);
  const [newKeyName, setNewKeyName] = useState('');

  // Webhooks state
  const [webhooks, setWebhooks] = useState<Webhook[]>([]);
  const [webhookUrl, setWebhookUrl] = useState('');
  const [webhookEvents, setWebhookEvents] = useState<WebhookEvent[]>([]);

  // Docs state
  const [endpoints] = useState<ApiEndpoint[]>(getEndpoints());
  const [expandedEndpoint, setExpandedEndpoint] = useState<string | null>(null);
  const [codeTab, setCodeTab] = useState<'curl' | 'javascript' | 'python'>('curl');

  // Usage state
  const [usageData, setUsageData] = useState<ApiUsageDay[]>([]);

  useEffect(() => {
    setKeys(getApiKeys());
    setWebhooks(getWebhooks());
    setUsageData(getUsageData());
  }, []);

  const copyToClipboard = useCallback((text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  }, []);

  // ── Key handlers ──

  const handleCreateKey = () => {
    if (!newKeyName.trim()) return;
    const key = createApiKey(newKeyName.trim());
    setKeys((prev) => [key, ...prev]);
    setNewKeyName('');
  };

  const handleRevokeKey = (id: string) => {
    revokeApiKey(id);
    setKeys(getApiKeys());
  };

  const handleRegenerateKey = (id: string) => {
    const updated = regenerateApiKey(id);
    if (updated) setKeys(getApiKeys());
  };

  // ── Webhook handlers ──

  const handleCreateWebhook = () => {
    if (!webhookUrl.trim() || webhookEvents.length === 0) return;
    const wh = createWebhook(webhookUrl.trim(), webhookEvents);
    setWebhooks((prev) => [wh, ...prev]);
    setWebhookUrl('');
    setWebhookEvents([]);
  };

  const handleDeleteWebhook = (id: string) => {
    deleteWebhook(id);
    setWebhooks(getWebhooks());
  };

  const handleToggleWebhook = (id: string) => {
    toggleWebhook(id);
    setWebhooks(getWebhooks());
  };

  const toggleWebhookEvent = (event: WebhookEvent) => {
    setWebhookEvents((prev) =>
      prev.includes(event) ? prev.filter((e) => e !== event) : [...prev, event]
    );
  };

  // ── Code examples ──

  const firstEndpoint = endpoints[0];
  const codeExamples = {
    curl: `curl -X GET "https://api.citedby.ai${firstEndpoint.path}?url=https://example.com" \\
  -H "Authorization: Bearer cb_live_your_api_key" \\
  -H "Content-Type: application/json"`,
    javascript: `const response = await fetch(
  'https://api.citedby.ai${firstEndpoint.path}?url=https://example.com',
  {
    method: 'GET',
    headers: {
      'Authorization': 'Bearer cb_live_your_api_key',
      'Content-Type': 'application/json',
    },
  }
);
const data = await response.json();
console.log(data);`,
    python: `import requests

response = requests.get(
    "https://api.citedby.ai${firstEndpoint.path}",
    params={"url": "https://example.com"},
    headers={
        "Authorization": "Bearer cb_live_your_api_key",
        "Content-Type": "application/json",
    },
)
data = response.json()
print(data)`,
  };

  const stats = getUsageStats();

  // ── Render helpers ──

  const renderMethodBadge = (method: 'GET' | 'POST') => (
    <span
      className={`text-xs font-bold px-2.5 py-1 rounded-md ${
        method === 'GET'
          ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
          : 'bg-blue-500/10 text-blue-400 border border-blue-500/20'
      }`}
    >
      {method}
    </span>
  );

  // ── Tab: Documentation ──

  const renderDocs = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Rate limits */}
      <div>
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">{t.apiDeveloperPage.rateLimits}</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {[
            { plan: 'Free', limit: '100/j', color: 'text-gray-300', border: 'border-white/[0.06]' },
            { plan: 'Pro', limit: '1,000/j', color: 'text-purple-400', border: 'border-purple-500/20' },
            { plan: 'Enterprise', limit: '10,000/j', color: 'text-amber-400', border: 'border-amber-500/20' },
          ].map((tier) => (
            <div
              key={tier.plan}
              className={`bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 text-center border ${tier.border}`}
            >
              <p className="text-sm text-gray-500 mb-1">{tier.plan}</p>
              <p className={`text-2xl font-bold ${tier.color}`}>{tier.limit}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Endpoints */}
      <div>
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">{t.apiDeveloperPage.endpoints}</h3>
        <div className="space-y-3">
          {endpoints.map((ep) => {
            const isOpen = expandedEndpoint === ep.path;
            return (
              <div key={ep.path} className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
                <button
                  onClick={() => setExpandedEndpoint(isOpen ? null : ep.path)}
                  className="w-full flex items-center gap-3 p-4 text-left hover:bg-white/[0.03]/50 transition-colors"
                >
                  {renderMethodBadge(ep.method)}
                  <code className="text-sm font-mono text-gray-200 flex-1">{ep.path}</code>
                  <span className="text-xs text-gray-500 hidden sm:inline mr-2">{ep.description.slice(0, 50)}...</span>
                  <span className="flex items-center gap-1 text-xs text-amber-400 mr-3">
                    <Zap size={12} /> {ep.gasCost} Gas
                  </span>
                  {isOpen ? <ChevronDown size={16} className="text-gray-500" /> : <ChevronRight size={16} className="text-gray-500" />}
                </button>
                {isOpen && (
                  <div className="border-t border-[var(--border-subtle)] p-4 space-y-4 animate-in fade-in duration-200">
                    <p className="text-sm text-gray-400">{ep.description}</p>

                    {ep.params.length > 0 && (
                      <div>
                        <h4 className="text-xs font-semibold text-gray-500 uppercase mb-2">{t.apiDeveloperPage.parameters}</h4>
                        <div className="overflow-x-auto">
                          <table className="w-full text-sm">
                            <thead>
                              <tr className="text-left text-gray-500 border-b border-[var(--border-subtle)]">
                                <th className="pb-2 pr-4 font-medium">{t.apiDeveloperPage.thName}</th>
                                <th className="pb-2 pr-4 font-medium">{t.apiDeveloperPage.thType}</th>
                                <th className="pb-2 pr-4 font-medium">{t.apiDeveloperPage.thRequired}</th>
                                <th className="pb-2 font-medium">{t.apiDeveloperPage.thDescription}</th>
                              </tr>
                            </thead>
                            <tbody>
                              {ep.params.map((p) => (
                                <tr key={p.name} className="border-b border-[var(--border-subtle)]">
                                  <td className="py-2 pr-4 font-mono text-purple-400">{p.name}</td>
                                  <td className="py-2 pr-4 text-gray-400">{p.type}</td>
                                  <td className="py-2 pr-4">
                                    {p.required ? (
                                      <span className="text-xs bg-red-500/10 text-red-400 px-1.5 py-0.5 rounded">{t.apiDeveloperPage.required}</span>
                                    ) : (
                                      <span className="text-xs bg-gray-500/10 text-gray-500 px-1.5 py-0.5 rounded">{t.apiDeveloperPage.optionalParam}</span>
                                    )}
                                  </td>
                                  <td className="py-2 text-gray-400">{p.description}</td>
                                </tr>
                              ))}
                            </tbody>
                          </table>
                        </div>
                      </div>
                    )}

                    <div>
                      <div className="flex items-center justify-between mb-2">
                        <h4 className="text-xs font-semibold text-gray-500 uppercase">{t.apiDeveloperPage.exampleResponse}</h4>
                        <button
                          onClick={() => copyToClipboard(ep.exampleResponse, `resp_${ep.path}`)}
                          className="flex items-center gap-1 text-xs text-gray-500 hover:text-gray-300 transition-colors"
                        >
                          {copiedId === `resp_${ep.path}` ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
                          {copiedId === `resp_${ep.path}` ? t.apiDeveloperPage.copied : t.apiDeveloperPage.copy}
                        </button>
                      </div>
                      <pre className="bg-black/50 border border-[var(--border-subtle)] rounded-lg p-4 text-xs font-mono text-gray-300 overflow-x-auto max-h-64 custom-scrollbar">
                        {ep.exampleResponse}
                      </pre>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Code examples */}
      <div>
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">{t.apiDeveloperPage.codeExamples}</h3>
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
          <div className="flex border-b border-[var(--border-subtle)]">
            {(['curl', 'javascript', 'python'] as const).map((tab) => (
              <button
                key={tab}
                onClick={() => setCodeTab(tab)}
                className={`px-4 py-2.5 text-sm font-medium transition-colors ${
                  codeTab === tab
                    ? 'text-purple-400 border-b-2 border-purple-500 bg-white/[0.03]/50'
                    : 'text-gray-500 hover:text-gray-300'
                }`}
              >
                {tab === 'curl' ? 'cURL' : tab === 'javascript' ? 'JavaScript' : 'Python'}
              </button>
            ))}
          </div>
          <div className="relative p-4">
            <button
              onClick={() => copyToClipboard(codeExamples[codeTab], `code_${codeTab}`)}
              className="absolute top-3 right-3 flex items-center gap-1 text-xs text-gray-500 hover:text-gray-300 transition-colors bg-black/40 px-2 py-1 rounded"
            >
              {copiedId === `code_${codeTab}` ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
              {copiedId === `code_${codeTab}` ? t.apiDeveloperPage.copied : t.apiDeveloperPage.copy}
            </button>
            <pre className="text-xs font-mono text-gray-300 overflow-x-auto custom-scrollbar whitespace-pre-wrap">
              {codeExamples[codeTab]}
            </pre>
          </div>
        </div>
      </div>
    </div>
  );

  // ── Tab: API Keys ──

  const renderKeys = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Create key form */}
      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
        <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
          <Plus size={16} className="text-purple-400" /> {t.apiDeveloperPage.newKey}
        </h3>
        <div className="flex gap-3">
          <input
            type="text"
            value={newKeyName}
            onChange={(e) => setNewKeyName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleCreateKey()}
            placeholder={t.apiDeveloperPage.keyPlaceholder}
            className="flex-1 bg-white/[0.03] border border-white/[0.06] rounded-lg px-4 py-2.5 text-sm text-gray-200 placeholder-gray-600 focus:outline-none focus:border-purple-500/40 transition-colors"
          />
          <button
            onClick={handleCreateKey}
            disabled={!newKeyName.trim()}
            className="btn-gradient px-5 py-2.5 text-sm text-white disabled:opacity-40 disabled:cursor-not-allowed"
          >
            {t.apiDeveloperPage.create}
          </button>
        </div>
      </div>

      {/* Keys list */}
      {keys.length === 0 ? (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-10 text-center">
          <Key size={32} className="text-[var(--text-disabled)] mx-auto mb-3" />
          <p className="text-gray-500 text-sm">{t.apiDeveloperPage.noKeys}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {keys.map((k) => (
            <div key={k.id} className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4 flex flex-col sm:flex-row sm:items-center gap-3">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-sm font-semibold text-white">{k.name}</span>
                  <span
                    className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                      k.status === 'active'
                        ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
                        : 'bg-red-500/10 text-red-400 border border-red-500/20'
                    }`}
                  >
                    {k.status === 'active' ? t.apiDeveloperPage.active : t.apiDeveloperPage.revoked}
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  <code className="text-xs font-mono text-gray-500">
                    {k.key.slice(0, 12)}...
                  </code>
                  <button
                    onClick={() => copyToClipboard(k.key, `key_${k.id}`)}
                    className="text-gray-500 hover:text-gray-300 transition-colors"
                    title={t.apiDeveloperPage.copyFullKey}
                  >
                    {copiedId === `key_${k.id}` ? (
                      <Check size={12} className="text-emerald-400" />
                    ) : (
                      <Copy size={12} />
                    )}
                  </button>
                </div>
                <p className="text-[11px] text-[var(--text-disabled)] mt-1">
                  {t.apiDeveloperPage.createdOn} {new Date(k.createdAt).toLocaleDateString('fr-FR')}
                </p>
              </div>
              <div className="flex items-center gap-2">
                {k.status === 'active' && (
                  <>
                    <button
                      onClick={() => handleRegenerateKey(k.id)}
                      className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-gray-200 bg-white/[0.03] hover:bg-white/[0.06] px-3 py-1.5 rounded-lg transition-colors"
                      title={t.apiDeveloperPage.regenerate}
                    >
                      <RefreshCw size={12} /> {t.apiDeveloperPage.regenerate}
                    </button>
                    <button
                      onClick={() => handleRevokeKey(k.id)}
                      className="flex items-center gap-1.5 text-xs text-red-400 hover:text-red-300 bg-red-500/5 hover:bg-red-500/10 px-3 py-1.5 rounded-lg transition-colors"
                      title={t.apiDeveloperPage.revoke}
                    >
                      <Shield size={12} /> {t.apiDeveloperPage.revoke}
                    </button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  // ── Tab: Webhooks ──

  const renderWebhooks = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Create webhook form */}
      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
        <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
          <Plus size={16} className="text-purple-400" /> {t.apiDeveloperPage.addWebhook}
        </h3>
        <div className="space-y-3">
          <input
            type="url"
            value={webhookUrl}
            onChange={(e) => setWebhookUrl(e.target.value)}
            placeholder="https://your-server.com/webhook"
            className="w-full bg-white/[0.03] border border-white/[0.06] rounded-lg px-4 py-2.5 text-sm text-gray-200 placeholder-gray-600 focus:outline-none focus:border-purple-500/40 transition-colors"
          />
          <div>
            <p className="text-xs text-gray-500 mb-2">{t.apiDeveloperPage.events}</p>
            <div className="flex flex-wrap gap-2">
              {WEBHOOK_EVENTS.map((ev) => {
                const selected = webhookEvents.includes(ev.value);
                return (
                  <button
                    key={ev.value}
                    onClick={() => toggleWebhookEvent(ev.value)}
                    className={`text-xs px-3 py-1.5 rounded-lg border transition-colors ${
                      selected
                        ? 'bg-purple-500/10 text-purple-400 border-purple-500/30'
                        : 'bg-white/[0.03]/50 text-gray-500 border-white/[0.06] hover:border-white/[0.15]'
                    }`}
                  >
                    {ev.label}
                  </button>
                );
              })}
            </div>
          </div>
          <button
            onClick={handleCreateWebhook}
            disabled={!webhookUrl.trim() || webhookEvents.length === 0}
            className="btn-gradient px-5 py-2.5 text-sm text-white disabled:opacity-40 disabled:cursor-not-allowed"
          >
            {t.apiDeveloperPage.add}
          </button>
        </div>
      </div>

      {/* Webhooks list */}
      {webhooks.length === 0 ? (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-10 text-center">
          <Globe size={32} className="text-[var(--text-disabled)] mx-auto mb-3" />
          <p className="text-gray-500 text-sm">{t.apiDeveloperPage.noWebhooks}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {webhooks.map((wh) => (
            <div key={wh.id} className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4">
              <div className="flex flex-col sm:flex-row sm:items-center gap-3">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-2">
                    <code className="text-sm font-mono text-gray-300 truncate max-w-[300px]" title={wh.url}>
                      {wh.url.length > 45 ? wh.url.slice(0, 45) + '...' : wh.url}
                    </code>
                  </div>
                  <div className="flex flex-wrap gap-1.5 mb-2">
                    {wh.events.map((ev) => (
                      <span
                        key={ev}
                        className={`text-[10px] font-medium px-2 py-0.5 rounded-full border ${EVENT_COLORS[ev]}`}
                      >
                        {ev}
                      </span>
                    ))}
                  </div>
                  <p className="text-[11px] text-[var(--text-disabled)]">
                    {wh.lastDelivery
                      ? `${t.apiDeveloperPage.lastDelivery} : ${new Date(wh.lastDelivery).toLocaleString('fr-FR')}`
                      : t.apiDeveloperPage.noDelivery}
                    {' '}{'\u00b7'} {t.apiDeveloperPage.createdOnShort} {new Date(wh.createdAt).toLocaleDateString('fr-FR')}
                  </p>
                </div>
                <div className="flex items-center gap-3">
                  <button
                    onClick={() => handleToggleWebhook(wh.id)}
                    className="text-gray-400 hover:text-gray-200 transition-colors"
                    title={wh.active ? t.apiDeveloperPage.deactivate : t.apiDeveloperPage.activate}
                  >
                    {wh.active ? (
                      <ToggleRight size={24} className="text-emerald-400" />
                    ) : (
                      <ToggleLeft size={24} className="text-[var(--text-disabled)]" />
                    )}
                  </button>
                  <button
                    onClick={() => handleDeleteWebhook(wh.id)}
                    className="text-gray-500 hover:text-red-400 transition-colors"
                    title={t.apiDeveloperPage.deleteWebhook}
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  // ── Tab: Usage ──

  const renderUsage = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* KPI cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-2">
            <Activity size={16} className="text-purple-400" />
            <span className="text-xs text-gray-500 uppercase tracking-wider">{t.apiDeveloperPage.requestsPerDay}</span>
          </div>
          <p className="text-2xl font-bold text-white">{stats.requestsPerDay}</p>
          <p className="text-xs text-[var(--text-disabled)] mt-1">{t.apiDeveloperPage.avg30Days}</p>
        </div>
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-2">
            <AlertTriangle size={16} className="text-amber-400" />
            <span className="text-xs text-gray-500 uppercase tracking-wider">{t.apiDeveloperPage.errorRate}</span>
          </div>
          <p className="text-2xl font-bold text-white">{stats.errorRate}%</p>
          <p className="text-xs text-[var(--text-disabled)] mt-1">{t.apiDeveloperPage.errorRatioDesc}</p>
        </div>
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-2">
            <Clock size={16} className="text-blue-400" />
            <span className="text-xs text-gray-500 uppercase tracking-wider">{t.apiDeveloperPage.avgLatency}</span>
          </div>
          <p className="text-2xl font-bold text-white">{stats.avgLatency} ms</p>
          <p className="text-xs text-[var(--text-disabled)] mt-1">{t.apiDeveloperPage.avgResponseTime}</p>
        </div>
      </div>

      {/* Chart */}
      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
        <h3 className="text-sm font-semibold text-white mb-4">{t.apiDeveloperPage.apiRequests30d}</h3>
        <div className="h-72">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={usageData} barGap={0}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
              <XAxis
                dataKey="date"
                tick={{ fill: '#6b7280', fontSize: 10 }}
                tickFormatter={(v: string) => v.slice(5)}
                axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
              />
              <YAxis
                tick={{ fill: '#6b7280', fontSize: 10 }}
                axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
              />
              <Tooltip
                contentStyle={{
                  background: '#1a1a1a',
                  border: '1px solid rgba(255,255,255,0.08)',
                  borderRadius: '8px',
                  fontSize: '12px',
                }}
                labelStyle={{ color: '#9ca3af' }}
              />
              <Legend
                wrapperStyle={{ fontSize: '12px', color: '#9ca3af' }}
              />
              <Bar dataKey="success" stackId="a" fill="#10b981" name={t.apiDeveloperPage.success} radius={[0, 0, 0, 0]} />
              <Bar dataKey="errors" stackId="a" fill="#ef4444" name={t.apiDeveloperPage.errors} radius={[2, 2, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* SDK section */}
      <div>
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">{t.apiDeveloperPage.officialSdks}</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
            <div className="flex items-center gap-2 mb-3">
              <Code2 size={16} className="text-amber-400" />
              <span className="text-sm font-semibold text-white">Node.js / JavaScript</span>
            </div>
            <div className="relative">
              <pre className="bg-black/50 border border-[var(--border-subtle)] rounded-lg p-3 text-xs font-mono text-gray-300">
                npm install @citedby/sdk
              </pre>
              <button
                onClick={() => copyToClipboard('npm install @citedby/sdk', 'sdk_npm')}
                className="absolute top-2 right-2 text-gray-500 hover:text-gray-300 transition-colors"
              >
                {copiedId === 'sdk_npm' ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
              </button>
            </div>
          </div>
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
            <div className="flex items-center gap-2 mb-3">
              <Terminal size={16} className="text-blue-400" />
              <span className="text-sm font-semibold text-white">Python</span>
            </div>
            <div className="relative">
              <pre className="bg-black/50 border border-[var(--border-subtle)] rounded-lg p-3 text-xs font-mono text-gray-300">
                pip install citedby
              </pre>
              <button
                onClick={() => copyToClipboard('pip install citedby', 'sdk_pip')}
                className="absolute top-2 right-2 text-gray-500 hover:text-gray-300 transition-colors"
              >
                {copiedId === 'sdk_pip' ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  // ── Main render ──

  return (
    <div className="page-enter">
      <PageHeader title={t.apiDeveloperPage.pageTitle} description={t.apiDeveloperPage.pageDescription} />
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-white">
              <span className="gradient-text">{t.apiDeveloperPage.title}</span> {t.apiDeveloperPage.titleAccent}
            </h1>
            <span className="bg-purple-500/10 text-purple-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-purple-500/20">
              {t.apiDeveloperPage.betaBadge}
            </span>
          </div>
          <p className="text-sm text-gray-500 mt-1">
            {t.apiDeveloperPage.subtitle}
          </p>
        </div>
      </div>

      {/* Tab bar */}
      <div className="flex gap-1 mb-6 border-b border-[var(--border-subtle)] overflow-x-auto">
        {TABS.map((tab) => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-4 py-3 text-sm font-medium whitespace-nowrap transition-colors border-b-2 ${
                isActive
                  ? 'text-purple-400 border-purple-500'
                  : 'text-gray-500 border-transparent hover:text-gray-300 hover:border-white/[0.06]'
              }`}
            >
              <Icon size={16} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Tab content */}
      {activeTab === 'docs' && renderDocs()}
      {activeTab === 'keys' && renderKeys()}
      {activeTab === 'webhooks' && renderWebhooks()}
      {activeTab === 'usage' && renderUsage()}
    </div>
  );
};

export default ApiDeveloper;

// pages/MultilingualCitations.tsx
// Analyse de citations multilingues — matrice langue x moteur IA

import React, { useState } from 'react';
import { Globe, Play, ChevronDown, ChevronUp, CheckCircle, XCircle, Loader2 } from 'lucide-react';
import { SUPPORTED_LANGUAGES, type LanguageCode } from '../services/v3/language-query-templates';
import { runMultilingualCheck, type MultilingualConfig, type MultilingualReport, type LanguageCitationResult } from '../services/v3/multilingual-checker';
import LanguageCitationMatrix from '../components/LanguageCitationMatrix';
import LanguageOpportunityCard from '../components/LanguageOpportunityCard';
import { useTranslation } from '../i18n/context';

interface Props {
  onBack?: () => void;
  user: { name: string; email: string } | null;
  onDeductCredits?: (amount: number) => void;
}

export default function MultilingualCitations({ onBack, user, onDeductCredits }: Props) {
  const { t } = useTranslation();

  // === CONFIG STATE ===
  const [url, setUrl] = useState('');
  const [brand, setBrand] = useState('');
  const [industry, setIndustry] = useState('');
  const [useCase, setUseCase] = useState('');
  const [selectedLanguages, setSelectedLanguages] = useState<LanguageCode[]>(['fr', 'en']);

  // === ANALYSIS STATE ===
  const [isRunning, setIsRunning] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, language: '', engine: '', status: '' });
  const [report, setReport] = useState<MultilingualReport | null>(null);
  const [expandedLanguage, setExpandedLanguage] = useState<string | null>(null);

  const creditCost = selectedLanguages.length * 3;

  function toggleLanguage(code: LanguageCode) {
    setSelectedLanguages(prev =>
      prev.includes(code) ? prev.filter(l => l !== code) : [...prev, code]
    );
  }

  async function handleAnalyze() {
    if (!url || !brand || !industry || selectedLanguages.length === 0) return;

    setIsRunning(true);
    setReport(null);
    try {
      const config: MultilingualConfig = {
        url, brand, industry, useCase: useCase || undefined,
        languages: selectedLanguages,
      };
      const result = await runMultilingualCheck(config, setProgress);
      setReport(result);
      onDeductCredits?.(creditCost);
    } catch (error) {
      console.error('Multilingual check failed:', error);
    } finally {
      setIsRunning(false);
    }
  }

  // Grouper les resultats par langue pour le detail accordion
  function getResultsByLanguage(lang: string): LanguageCitationResult[] {
    return report?.results.filter(r => r.language === lang) || [];
  }

  return (
    <div className="space-y-6 page-enter">

      {/* === HEADER === */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <Globe className="w-6 h-6 text-blue-400" />
            {t.multilingualPage.title}
          </h1>
          <p className="text-[14px] text-zinc-400 mt-1">
            {t.multilingualPage.subtitle}
          </p>
        </div>
        {report && (
          <div className="text-right">
            <div className="text-[13px] text-zinc-500">{t.multilingualPage.analysisDate}</div>
            <div className="text-[14px] text-zinc-300 font-medium">
              {new Date(report.timestamp).toLocaleDateString('fr-FR')}
            </div>
          </div>
        )}
      </div>

      {/* === CONFIGURATION === */}
      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
        <h2 className="text-white font-semibold mb-4">{t.multilingualPage.configuration}</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">{t.multilingualPage.siteUrl}</label>
            <input
              type="url"
              value={url}
              onChange={e => setUrl(e.target.value)}
              placeholder="https://example.com"
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">{t.multilingualPage.brandName}</label>
            <input
              type="text"
              value={brand}
              onChange={e => setBrand(e.target.value)}
              placeholder="Ma Marque"
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">{t.multilingualPage.industry}</label>
            <input
              type="text"
              value={industry}
              onChange={e => setIndustry(e.target.value)}
              placeholder="SaaS, Marketing digital, E-commerce..."
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">{t.multilingualPage.useCase} <span className="text-zinc-600">({t.multilingualPage.useCaseOptional})</span></label>
            <input
              type="text"
              value={useCase}
              onChange={e => setUseCase(e.target.value)}
              placeholder="SEO, gestion de projet..."
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
        </div>

        {/* Language selection */}
        <div className="mb-6">
          <label className="block text-[13px] text-zinc-400 mb-3">{t.multilingualPage.languagesToAnalyze}</label>
          <div className="flex flex-wrap gap-2">
            {SUPPORTED_LANGUAGES.map(lang => {
              const isSelected = selectedLanguages.includes(lang.code as LanguageCode);
              return (
                <button
                  key={lang.code}
                  onClick={() => toggleLanguage(lang.code as LanguageCode)}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[13px] font-medium transition-all duration-150 cursor-pointer ${
                    isSelected
                      ? 'bg-blue-500/15 text-blue-400 border border-blue-500/30'
                      : 'bg-white/[0.03] text-zinc-500 border border-white/[0.06] hover:text-zinc-300 hover:border-white/[0.1]'
                  }`}
                >
                  <span>{lang.flag}</span>
                  <span>{lang.label}</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Cost + Launch */}
        <div className="flex items-center justify-between pt-4 border-t border-white/[0.06]">
          <div className="text-[14px] text-zinc-400">
            {t.multilingualPage.cost} : <span className="text-white font-medium">{creditCost} {t.multilingualPage.credits}</span>
            <span className="text-zinc-600 ml-1">({t.multilingualPage.creditsPerLang} {selectedLanguages.length} {selectedLanguages.length > 1 ? t.multilingualPage.languages : t.multilingualPage.language})</span>
          </div>
          <button
            onClick={handleAnalyze}
            disabled={isRunning || !url || !brand || !industry || selectedLanguages.length === 0}
            className="flex items-center gap-2 px-5 py-2.5 rounded-lg bg-white text-black font-medium text-[14px] hover:bg-gray-200 disabled:opacity-40 disabled:cursor-not-allowed transition-all cursor-pointer press-effect"
          >
            {isRunning ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                {t.multilingualPage.analyzing}
              </>
            ) : (
              <>
                <Play className="w-4 h-4" />
                {t.multilingualPage.launchAnalysis} — {creditCost} {t.multilingualPage.credits}
              </>
            )}
          </button>
        </div>
      </div>

      {/* === PROGRESS BAR === */}
      {isRunning && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-[14px] text-white font-medium">
              {t.multilingualPage.progressLabel} {progress.current}/{progress.total} {t.multilingualPage.queries}
            </span>
            <span className="text-[13px] text-zinc-500">
              {Math.round((progress.current / Math.max(progress.total, 1)) * 100)}%
            </span>
          </div>
          <div className="h-2 rounded-full bg-white/[0.06] overflow-hidden">
            <div
              className="h-full rounded-full bg-blue-500 transition-all duration-300 skeleton-shimmer"
              style={{ width: `${(progress.current / Math.max(progress.total, 1)) * 100}%` }}
            />
          </div>
          <p className="text-[13px] text-zinc-500 mt-2">
            {progress.status}
          </p>
        </div>
      )}

      {/* === RESULTATS === */}
      {report && (
        <>
          {/* Global stats */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <StatCard
              label={t.multilingualPage.bestLanguage}
              value={`${SUPPORTED_LANGUAGES.find(l => l.code === report.globalStats.bestLanguage.code)?.flag || ''} ${report.globalStats.bestLanguage.rate}%`}
              color="text-emerald-400"
            />
            <StatCard
              label={t.multilingualPage.worstLanguage}
              value={`${SUPPORTED_LANGUAGES.find(l => l.code === report.globalStats.worstLanguage.code)?.flag || ''} ${report.globalStats.worstLanguage.rate}%`}
              color="text-red-400"
            />
            <StatCard
              label={t.multilingualPage.avgRate}
              value={`${report.globalStats.averageRate}%`}
              color="text-blue-400"
            />
            <StatCard
              label={t.multilingualPage.queriesAnalyzed}
              value={`${report.globalStats.totalQueriesRun}`}
              subtext={`${report.globalStats.totalCitations} ${t.multilingualPage.citationsCount}`}
              color="text-zinc-300"
            />
          </div>

          {/* Citation Matrix */}
          <LanguageCitationMatrix summaries={report.summaryByLanguage} />

          {/* Opportunities */}
          {report.opportunities.length > 0 && (
            <div>
              <h2 className="text-white font-semibold text-lg mb-4">{t.multilingualPage.opportunities}</h2>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                {report.opportunities.map((opp, i) => (
                  <LanguageOpportunityCard key={i} opportunity={opp} />
                ))}
              </div>
            </div>
          )}

          {/* Detail accordion */}
          <div>
            <h2 className="text-white font-semibold text-lg mb-4">{t.multilingualPage.detailByQuery}</h2>
            <div className="space-y-2">
              {report.summaryByLanguage.map(summary => {
                const langInfo = SUPPORTED_LANGUAGES.find(l => l.code === summary.language);
                const isExpanded = expandedLanguage === summary.language;
                const langResults = getResultsByLanguage(summary.language);
                const citedCount = langResults.filter(r => r.cited).length;

                return (
                  <div key={summary.language} className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
                    <button
                      onClick={() => setExpandedLanguage(isExpanded ? null : summary.language)}
                      className="w-full flex items-center justify-between px-5 py-4 hover:bg-white/[0.02] transition-colors cursor-pointer"
                    >
                      <div className="flex items-center gap-3">
                        <span className="text-lg">{langInfo?.flag}</span>
                        <span className="text-[14px] text-white font-medium">{langInfo?.label}</span>
                        <span className="text-[13px] text-zinc-500">
                          ({citedCount}/{langResults.length} {t.multilingualPage.citationsCount}, {summary.overallRate}%)
                        </span>
                      </div>
                      {isExpanded ? <ChevronUp className="w-4 h-4 text-zinc-500" /> : <ChevronDown className="w-4 h-4 text-zinc-500" />}
                    </button>

                    {isExpanded && (
                      <div className="border-t border-white/[0.04] divide-y divide-white/[0.04]">
                        {/* Group by query */}
                        {groupByQuery(langResults).map(group => (
                          <div key={group.queryId} className="px-5 py-3">
                            <p className="text-[13px] text-zinc-300 font-medium mb-2">
                              &laquo; {group.query} &raquo;
                            </p>
                            <div className="flex flex-wrap gap-3">
                              {group.engines.map(eng => (
                                <div key={eng.engine} className="flex items-center gap-1.5 text-[13px]">
                                  <span className={`font-medium ${
                                    eng.engine === 'chatgpt' ? 'text-emerald-400' :
                                    eng.engine === 'perplexity' ? 'text-blue-400' : 'text-purple-400'
                                  }`}>
                                    {eng.engine}
                                  </span>
                                  {eng.cited ? (
                                    <CheckCircle className="w-3.5 h-3.5 text-emerald-400" />
                                  ) : (
                                    <XCircle className="w-3.5 h-3.5 text-zinc-600" />
                                  )}
                                  <span className="text-zinc-500">
                                    {eng.cited ? `(${eng.position}, ${eng.sentiment})` : t.multilingualPage.notCited}
                                  </span>
                                </div>
                              ))}
                            </div>
                            {group.competitors.length > 0 && (
                              <p className="text-[12px] text-zinc-600 mt-1">
                                {t.multilingualPage.competitorsCited} : {group.competitors.join(', ')}
                              </p>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

// === HELPERS ===

function StatCard({ label, value, subtext, color }: { label: string; value: string; subtext?: string; color: string }) {
  return (
    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
      <div className="text-[11px] uppercase tracking-wider text-zinc-600 font-medium">{label}</div>
      <div className={`text-2xl font-bold mt-1 ${color}`}>{value}</div>
      {subtext && <div className="text-[13px] text-zinc-500 mt-0.5">{subtext}</div>}
    </div>
  );
}

interface QueryGroup {
  queryId: string;
  query: string;
  engines: { engine: string; cited: boolean; position: string; sentiment: string }[];
  competitors: string[];
}

function groupByQuery(results: LanguageCitationResult[]): QueryGroup[] {
  const groups: Record<string, QueryGroup> = {};

  for (const r of results) {
    if (!groups[r.queryId]) {
      groups[r.queryId] = {
        queryId: r.queryId,
        query: r.query,
        engines: [],
        competitors: [],
      };
    }
    groups[r.queryId].engines.push({
      engine: r.engine,
      cited: r.cited,
      position: r.position,
      sentiment: r.sentiment,
    });
    for (const comp of r.competitorsCited) {
      if (!groups[r.queryId].competitors.includes(comp)) {
        groups[r.queryId].competitors.push(comp);
      }
    }
  }

  return Object.values(groups);
}

